const grpc = require('grpc');
const protoLoader = require('@grpc/proto-loader');

// Load the .proto file
const packageDefinition = protoLoader.loadSync(
  'path/to/your/service.proto',
  {
    keepCase: true,
    longs: String,
    enums: String,
    defaults: true,
    oneofs: true,
  }
);
const yourPackage = grpc.loadPackageDefinition(packageDefinition).YourPackageName;

// Create a gRPC client
function createGrpcClient(address) {
  return new yourPackage.YourService(address, grpc.credentials.createInsecure());
}

// Function to forward headers to gRPC services
async function forwardHeadersToGrpc(requestHeaders, grpcClientMethod, requestData) {
  const metadata = new grpc.Metadata();

  // Add custom headers to the metadata
  Object.keys(requestHeaders).forEach((headerKey) => {
    if (['user-agent', 'x-forwarded-for'].includes(headerKey.toLowerCase())) {
      metadata.add(headerKey, requestHeaders[headerKey]);
    }
  });

  // Call the gRPC method with metadata
  return new Promise((resolve, reject) => {
    grpcClientMethod(requestData, metadata, (err, response) => {
      if (err) {
        reject(err);
      } else {
        resolve(response);
      }
    });
  });
}

// Example usage in an HTTP request handler
const express = require('express');
const app = express();

app.use(express.json());

app.post('/your-endpoint', async (req, res) => {
  const grpcClient = createGrpcClient('localhost:50051');
  
  try {
    const result = await forwardHeadersToGrpc(req.headers, grpcClient.yourMethod, req.body);
    res.send(result);
  } catch (error) {
    res.status(500).send({ error: 'Failed to call gRPC service' });
  }
});

